#include <bits/stdc++.h>
using namespace std;
int main(){string s;getline(cin,s);stack<char>st;bool ok=true;for(char c:s){if(c=='('||c=='['||c=='{')st.push(c);else if(c==')'||c==']'||c=='}'){char need=c==')'?'(':c==']'?'[':'{';if(st.empty()||st.top()!=need){ok=false;break;}st.pop();}}if(!st.empty())ok=false;printf("%s\n",ok?"yes":"no");}
